import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.UUID;

@Service
public class RedisDistributedLock {
    private final RedisTemplate<String, String> redis;

    RedisDistributedLock(RedisTemplate<String,String> r) { redis = r; }

    // SET key uuid NX EX ttlSeconds
    public String tryAcquire(String key, Duration ttl) {
        String value = UUID.randomUUID().toString();
        Boolean ok   = redis.opsForValue().setIfAbsent(key, value, ttl);
        return Boolean.TRUE.equals(ok) ? value : null;
    }

    // GET key → compare → DEL key (non-atomic but safe enough for most uses)
    public boolean release(String key, String lockValue) {
        String current = redis.opsForValue().get(key);
        if (lockValue.equals(current)) {
            redis.delete(key);
            return true;
        }
        return false;  // TTL expired and re-acquired by another, OR already released
    }

    // Convenience: acquire → run → release (try-finally)
    public boolean runOnce(String key, Duration ttl, Runnable task) {
        String lockValue = tryAcquire(key, ttl);
        if (lockValue == null) return false;  // not acquired

        try {
            task.run();
            return true;
        } finally {
            release(key, lockValue);  // always releases, even on exception
        }
    }
}

