@Service
public class SwiggyDailyDealsJob {
    private final RedisDistributedLock lock;
    private final String instanceId = UUID.randomUUID().toString().substring(0, 8);

    SwiggyDailyDealsJob(RedisDistributedLock l) { lock = l; }

    @Scheduled(cron = "0 0 2 * * *")  // 2:00 AM daily
    public void refreshDailyDeals() {
        // Date in key: naturally resets each day
        String key = "lock:daily-deals:" + LocalDate.now().toString();

        boolean ran = lock.runOnce(key, java.time.Duration.ofMinutes(30), () -> {
            System.out.printf("[%s] Refreshing daily deals...%n", instanceId);
            // ... load new deals, clear old caches, notify restaurants ...
            System.out.printf("[%s] Daily deals refresh complete.%n", instanceId);
        });

        if (!ran) {
            System.out.printf("[%s] Skipped — daily deals refresh already running.%n", instanceId);
        }
    }

    // CRASH SCENARIO:
    // Instance A: acquires lock, starts job at 2:00am
    // At 2:15am: Instance A crashes (OOM, hardware failure)
    // Lock: still in Redis with TTL = 30 min, expires at 2:30am
    // At 2:30am: lock expires automatically (TTL design!)
    // At next day 2:00am: fresh key 'lock:daily-deals:2024-06-16'
    //   → any instance can acquire and run
    // Today (2024-06-15): deals were NOT refreshed (job failed)
    //   → monitoring alert should fire
    //   → on-call engineer can manually trigger or it runs tomorrow
}

