import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;

@Service
public class PaymentIdempotencyService {
    private final RedisTemplate<String, String> redis;

    PaymentIdempotencyService(RedisTemplate<String,String> r) { redis=r; }

    public String processPayment(String idempotencyKey, String amount) {
        String resultKey = "idem:result:" + idempotencyKey;
        String lockKey   = "idem:lock:"   + idempotencyKey;

        // RETRY PATH: result already cached → return immediately
        String cached = redis.opsForValue().get(resultKey);
        if (cached != null) {
            System.out.println("Idempotency HIT for " + idempotencyKey + " → " + cached);
            return cached;
        }

        // Acquire processing lock (30s — enough for payment roundtrip):
        Boolean acquired = redis.opsForValue()
            .setIfAbsent(lockKey, "processing", Duration.ofSeconds(30));

        if (!Boolean.TRUE.equals(acquired)) {
            throw new RuntimeException(
                "Payment " + idempotencyKey + " is already being processed");
        }

        try {
            // Double-check after acquiring lock:
            String check = redis.opsForValue().get(resultKey);
            if (check != null) return check;

            // HAPPY PATH: process payment:
            String paymentId = "PAY-" + System.currentTimeMillis();
            String result    = "{\"paymentId\":\"" + paymentId + "\",\"status\":\"success\"}";
            System.out.println("Processing payment " + idempotencyKey + " → " + paymentId);

            // Cache result for 24h (covers client retry window):
            redis.opsForValue().set(resultKey, result, Duration.ofHours(24));
            return result;
        } finally {
            redis.delete(lockKey);
        }
    }

    public static void main(String[] args) {
        System.out.println("Happy path: new key → lock → process → cache result");
        System.out.println("Retry path: cached result → return immediately (no DB call)");
        System.out.println("In-flight: lock exists → throw PaymentInProgressException");
    }
}

