import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.UUID;

@Service
public class LockWithRetry {
    private final RedisTemplate<String, String> redis;
    private static final int RETRY_INTERVAL_MS = 50;

    LockWithRetry(RedisTemplate<String,String> r) { redis=r; }

    // Wait up to maxWaitMs for the lock:
    public String tryAcquireWithWait(String key, Duration ttl, long maxWaitMs) {
        long deadline = System.currentTimeMillis() + maxWaitMs;

        while (System.currentTimeMillis() < deadline) {
            String value = UUID.randomUUID().toString();
            Boolean ok = redis.opsForValue().setIfAbsent(key, value, ttl);
            if (Boolean.TRUE.equals(ok)) return value;  // acquired!

            try { Thread.sleep(RETRY_INTERVAL_MS); }
            catch (InterruptedException e) { Thread.currentThread().interrupt(); break; }
        }
        throw new LockTimeoutException("Could not acquire lock '" + key + "' within " + maxWaitMs + "ms");
    }

    // Simple non-blocking acquire (from Topic):
    public String tryAcquire(String key, Duration ttl) {
        String value = UUID.randomUUID().toString();
        Boolean ok = redis.opsForValue().setIfAbsent(key, value, ttl);
        return Boolean.TRUE.equals(ok) ? value : null;
    }

    // WHEN TO USE EACH:
    // tryAcquire (non-blocking):
    //   @Scheduled jobs: skip if already running (don't wait — just skip this run)
    //   Idempotency: if in-flight, return 409 immediately
    //   Best for: jobs where skipping is acceptable

    // tryAcquireWithWait (blocking):
    //   Critical operations where you MUST complete (e.g., completing a user's action)
    //   Short-lived locks where waiting is better than failing
    //   Best for: user-facing operations that can't silently skip

    static class LockTimeoutException extends RuntimeException {
        LockTimeoutException(String m) { super(m); }
    }

    public static void main(String[] a) {
        System.out.println("tryAcquire: non-blocking, returns null if locked");
        System.out.println("tryAcquireWithWait: blocks up to maxWaitMs, throws on timeout");
    }
}

