import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.data.redis.core.RedisTemplate;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

@SpringBootTest
class DistributedLockTest {
    @Autowired RedisDistributedLock lock;
    @Autowired RedisTemplate<String,String> redis;

    private final String TEST_KEY = "lock:test:" + System.currentTimeMillis();

    @AfterEach void cleanup() { redis.delete(TEST_KEY); }

    @Test void onlyOneAcquires_outOfTwo() throws Exception {
        AtomicInteger successCount = new AtomicInteger(0);
        AtomicInteger failCount    = new AtomicInteger(0);
        CountDownLatch latch = new CountDownLatch(2);

        Runnable attempt = () -> {
            String val = lock.tryAcquire(TEST_KEY, Duration.ofMinutes(1));
            if (val != null) successCount.incrementAndGet();
            else             failCount.incrementAndGet();
            latch.countDown();
        };

        new Thread(attempt).start();
        new Thread(attempt).start();
        latch.await(5, TimeUnit.SECONDS);

        assertEquals(1, successCount.get(), "Exactly one should acquire the lock");
        assertEquals(1, failCount.get(),    "Exactly one should fail to acquire");
    }

    @Test void keyExists_afterAcquire() {
        String val = lock.tryAcquire(TEST_KEY, Duration.ofMinutes(1));
        assertNotNull(val, "Should acquire lock");
        assertTrue(redis.hasKey(TEST_KEY), "Key should exist in Redis");
    }

    @Test void keyGone_afterRelease() {
        String val = lock.tryAcquire(TEST_KEY, Duration.ofMinutes(1));
        assertNotNull(val);
        lock.release(TEST_KEY, val);
        assertFalse(Boolean.TRUE.equals(redis.hasKey(TEST_KEY)), "Key should be gone");
    }
}

