@Service
public class IdempotentOrderService {
    private final RedisTemplate<String, String> redis;
    // Track actual confirmations for test verification:
    public final AtomicInteger confirmationCount = new AtomicInteger(0);

    IdempotentOrderService(RedisTemplate<String,String> r) { redis=r; }

    public String confirmOrder(String idempotencyKey, String orderId) {
        String resultKey = "idem:result:" + idempotencyKey;
        String lockKey   = "idem:lock:"   + idempotencyKey;

        // Fast path — already confirmed:
        String cached = redis.opsForValue().get(resultKey);
        if (cached != null) {
            System.out.println("[IDEM HIT] Returning cached result for " + idempotencyKey);
            return cached;
        }

        // Slow path — need to process:
        Boolean acquired = redis.opsForValue()
            .setIfAbsent(lockKey, "1", Duration.ofSeconds(30));
        if (!Boolean.TRUE.equals(acquired)) {
            throw new RuntimeException("Confirmation in progress for " + idempotencyKey);
        }

        try {
            // Double-check:
            String recheck = redis.opsForValue().get(resultKey);
            if (recheck != null) return recheck;

            // Actually confirm:
            confirmationCount.incrementAndGet();  // track for test assertion
            String result = "{\"orderId\":\"" + orderId + "\",\"status\":\"CONFIRMED\"}";
            System.out.println("[CONFIRM] Order " + orderId + " confirmed");

            // Cache result:
            redis.opsForValue().set(resultKey, result, Duration.ofHours(6));
            return result;
        } finally {
            redis.delete(lockKey);
        }
    }

    public static void main(String[] a) {
        System.out.println("Call 1: process + cache result");
        System.out.println("Call 2 (same key): return cached, do NOT process again");
        System.out.println("confirmationCount after 2 calls: 1 (not 2!)");
    }
}

