import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.UUID;

@Service
public class LeaderElectionService {
    private static final String LOCK_KEY    = "lock:leader";
    private static final Duration LEADER_TTL = Duration.ofSeconds(30);

    private final RedisTemplate<String, String> redis;
    private final String instanceId = UUID.randomUUID().toString();
    private volatile String currentLockValue = null;

    LeaderElectionService(RedisTemplate<String,String> r) { redis=r; }

    public boolean tryBecomeLeader() {
        String value = instanceId;
        Boolean ok = redis.opsForValue().setIfAbsent(LOCK_KEY, value, LEADER_TTL);
        if (Boolean.TRUE.equals(ok)) {
            currentLockValue = value;
            System.out.println("[" + instanceId.substring(0,8) + "] Became leader!");
            return true;
        }
        return false;
    }

    // Called @Scheduled every 20s to renew before 30s TTL expires:
    @Scheduled(fixedRate = 20_000)
    public void renewLeadership() {
        if (currentLockValue == null) {
            tryBecomeLeader();  // try to take leadership if no one holds it
            return;
        }
        String current = redis.opsForValue().get(LOCK_KEY);
        if (instanceId.equals(current)) {
            redis.expire(LOCK_KEY, LEADER_TTL);  // refresh TTL
            System.out.println("[" + instanceId.substring(0,8) + "] Leadership renewed");
        } else {
            // Lost leadership (TTL expired before renewal):
            currentLockValue = null;
            System.out.println("[" + instanceId.substring(0,8) + "] Lost leadership");
        }
    }

    public boolean isLeader() {
        return instanceId.equals(redis.opsForValue().get(LOCK_KEY));
    }

    public void stepDown() {
        String current = redis.opsForValue().get(LOCK_KEY);
        if (instanceId.equals(current)) {
            redis.delete(LOCK_KEY);
            currentLockValue = null;
            System.out.println("[" + instanceId.substring(0,8) + "] Stepped down");
        }
    }
}

