import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.concurrent.atomic.AtomicInteger;

@Service
public class IdempotentPaymentProcessor {
    public final AtomicInteger processCount = new AtomicInteger(0);
    private final RedisTemplate<String, String> redis;

    IdempotentPaymentProcessor(RedisTemplate<String,String> r) { redis=r; }

    public String process(String idempotencyKey, String merchantId, double amount) {
        String resultKey = "pay:result:" + idempotencyKey;
        String lockKey   = "pay:lock:"   + idempotencyKey;

        // State 1: COMPLETED
        String cached = redis.opsForValue().get(resultKey);
        if (cached != null) {
            System.out.println("[CACHED] " + idempotencyKey);
            return cached;
        }

        // State 2: IN_PROGRESS
        Boolean acquired = redis.opsForValue()
            .setIfAbsent(lockKey, "in-progress", Duration.ofSeconds(30));
        if (!Boolean.TRUE.equals(acquired)) {
            throw new RuntimeException("409: payment " + idempotencyKey + " in progress");
        }

        try {
            // Double-check after lock:
            String recheck = redis.opsForValue().get(resultKey);
            if (recheck != null) return recheck;

            // State 3: NOT_STARTED — process it:
            processCount.incrementAndGet();
            String payId = "PAY-" + System.currentTimeMillis();
            System.out.printf("[PROCESS] %s → %s (₹%.2f)%n", idempotencyKey, payId, amount);

            String result = "{\"id\":\"" + payId + "\",\"merchant\":\"" + merchantId +
                "\",\"amount\":" + amount + ",\"status\":\"captured\"}";

            // Only cache on SUCCESS — failure leaves no result → allows clean retry
            redis.opsForValue().set(resultKey, result, Duration.ofHours(24));
            return result;

        } catch (Exception e) {
            // On failure: delete lock but NOT result
            // → next call can retry (no cached failure)
            System.err.println("[FAILED] " + idempotencyKey + ": " + e.getMessage());
            throw e;  // lock deleted in finally
        } finally {
            redis.delete(lockKey);
        }
    }

    public static void main(String[] a) {
        System.out.println("Call 1: process + cache result → processCount=1");
        System.out.println("Call 2 (same key): return cached → processCount still 1");
    }
}

