import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.data.redis.core.script.DefaultRedisScript;
import org.springframework.stereotype.Service;
import java.time.Duration;
import java.util.*;
import java.util.UUID;

@Service
public class AtomicLockReleaseService {
    private final RedisTemplate<String, String> redis;

    // Lua script: atomic compare-and-delete
    private static final DefaultRedisScript<Long> RELEASE_SCRIPT =
        new DefaultRedisScript<>(
            // KEYS[1] = lock key, ARGV[1] = expected value
            "if redis.call('get', KEYS[1]) == ARGV[1] then " +
            "  return redis.call('del', KEYS[1]) " +
            "else " +
            "  return 0 " +
            "end",
            Long.class
        );

    AtomicLockReleaseService(RedisTemplate<String,String> r) { redis=r; }

    public String tryAcquire(String key, Duration ttl) {
        String value = UUID.randomUUID().toString();
        Boolean ok = redis.opsForValue().setIfAbsent(key, value, ttl);
        return Boolean.TRUE.equals(ok) ? value : null;
    }

    // Atomic: compare + delete in one operation (no gap for other threads)
    public boolean atomicRelease(String key, String value) {
        Long result = redis.execute(
            RELEASE_SCRIPT,
            List.of(key),    // KEYS[1]
            value             // ARGV[1]
        );
        return Long.valueOf(1L).equals(result);
    }

    public static void main(String[] args) {
        System.out.println("Non-atomic release: GET → compare → DEL (gap between GET and DEL!)");
        System.out.println("Atomic Lua:        if GET==value: DEL (one Redis command, no gap)");
        System.out.println("");
        System.out.println("Race in non-atomic:");
        System.out.println("  T1: GET key → 'uuid-A' (matches our value)");
        System.out.println("  TTL expires here!");
        System.out.println("  T2: SETNX key → acquires with 'uuid-B'");
        System.out.println("  T1: DEL key → deletes T2's lock! Bug!");
        System.out.println("");
        System.out.println("Lua is atomic: no other command can execute between GET and DEL");
    }
}

import org.springframework.data.redis.core.*;
import org.springframework.data.redis.core.script.DefaultRedisScript;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
