import java.time.*;
import java.util.*;
import java.util.concurrent.atomic.*;

@Service
class RedisDLock {
    private final RedisTemplate<String,String> r;
    private static final DefaultRedisScript<Long> RL=new DefaultRedisScript<>(
        "if redis.call('get',KEYS[1])==ARGV[1] then return redis.call('del',KEYS[1]) else return 0 end",Long.class);
    RedisDLock(RedisTemplate<String,String> r){this.r=r;}
    public String acquire(String k,Duration t){
        String v=UUID.randomUUID().toString();
        Boolean ok=r.opsForValue().setIfAbsent(k,v,t);
        return Boolean.TRUE.equals(ok)?v:null;
    }
    public boolean release(String k,String v){
        return Long.valueOf(1L).equals(r.execute(RL,List.of(k),v));
    }
    public boolean runOnce(String k,Duration t,Runnable task){
        String v=acquire(k,t); if(v==null) return false;
        try{task.run();return true;}finally{release(k,v);}
    }
}

@Service
class DailyReconciliationJob {
    public final AtomicInteger runs=new AtomicInteger(0);
    private final RedisDLock lock;
    DailyReconciliationJob(RedisDLock l){lock=l;}
    @Scheduled(cron="0 0 2 * * *")
    public void reconcile(){
        String k="lock:reconcile:"+LocalDate.now();
        lock.runOnce(k,Duration.ofHours(2),()->{
            runs.incrementAndGet();
            System.out.println("[Reconcile] Running for "+LocalDate.now());
        });
    }
    public boolean runForDate(LocalDate d){
        return lock.runOnce("lock:reconcile:"+d,Duration.ofHours(2),()->{
            runs.incrementAndGet();
        });
    }
}

@Service
class IdempotentChargeProcessor {
    public final AtomicInteger charges=new AtomicInteger(0);
    private final RedisTemplate<String,String> redis;
    private final RedisDLock lock;
    IdempotentChargeProcessor(RedisTemplate<String,String> r,RedisDLock l){redis=r;lock=l;}
    public String charge(String iKey,double amount){
        String rk="charge:result:"+iKey; String lk="charge:lock:"+iKey;
        String cached=redis.opsForValue().get(rk);
        if(cached!=null)return cached;
        String lv=lock.acquire(lk,Duration.ofSeconds(30));
        if(lv==null) throw new RuntimeException("in-progress");
        try{
            String rc=redis.opsForValue().get(rk);
            if(rc!=null)return rc;
            charges.incrementAndGet();
            String result="charged:"+amount;
            redis.opsForValue().set(rk,result,Duration.ofHours(24));
            return result;
        }finally{lock.release(lk,lv);}
    }
}

@SpringBootTest
class RazorpayCoordinatorTest{
    @Autowired DailyReconciliationJob job;
    @Autowired IdempotentChargeProcessor proc;
    @Autowired RedisTemplate<String,String> redis;
    LocalDate today=LocalDate.now();
    @BeforeEach void clean(){
        redis.delete("lock:reconcile:"+today);
        redis.delete("charge:result:KEY1"); redis.delete("charge:lock:KEY1");
        job.runs.set(0); proc.charges.set(0);
    }
    @Test void reconcile_runsOnce(){
        assertTrue(job.runForDate(today));
        assertFalse(job.runForDate(today));
        assertEquals(1,job.runs.get());
    }
    @Test void charge_idempotent(){
        proc.charge("KEY1",999.0);
        proc.charge("KEY1",999.0);
        assertEquals(1,proc.charges.get(),"Should charge only once");
    }
}
